B.azB=s(["\xa7 1 KSchG","\xa7 23 KSchG"],t.s)
B.RL=new A.hP(B.ko,"Gilt der K\xfcndigungsschutz f\xfcr mich?","Das K\xfcndigungsschutzgesetz greift erst ab bestimmten Voraussetzungen.",B.aNB,B.azB)
B.RE=new A.cM("Nur schriftlich","Eine K\xfcndigung muss schriftlich mit eigenh\xe4ndiger Unterschrift erfolgen (\xa7 623 BGB). Eine K\xfcndigung per E-Mail, SMS oder Messenger ist unwirksam.")
B.Rx=new A.cM("Betriebsrat anh\xf6ren","Gibt es einen Betriebsrat, muss er vor jeder K\xfcndigung angeh\xf6rt werden (\xa7 102 BetrVG). Ohne ordnungsgem\xe4\xdfe Anh\xf6rung ist die K\xfcndigung unwirksam.")
B.RC=new A.cM("K\xfcndigungsfristen","Die gesetzlichen Fristen richten sich nach \xa7 622 BGB und verl\xe4ngern sich f\xfcr Arbeitgeberk\xfcndigungen mit der Dauer der Betriebszugeh\xf6rigkeit. Im Vertrag oder Tarifvertrag k\xf6nnen abweichende Fristen stehen.")
